<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Expense Tracker</title>
    <style>
        :root {
            --primary: #2563eb;
            --danger: #dc2626;
            --bg: #f8fafc;
            --card: #ffffff;
            --text: #1e293b;
            --border: #e2e8f0;
        }

        body {
            font-family: system-ui, -apple-system, sans-serif;
            background-color: var(--bg);
            color: var(--text);
            line-height: 1.5;
            margin: 0;
            padding: 20px;
            display: flex;
            justify-content: center;
        }

        #app {
            width: 100%;
            max-width: 600px;
            background: var(--card);
            padding: 2rem;
            border-radius: 8px;
            box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
        }

        h1 { margin-top: 0; font-size: 1.5rem; }

        form, .filter-section, .summary-section {
            margin-bottom: 2rem;
            padding-bottom: 1.5rem;
            border-bottom: 1px solid var(--border);
        }

        form:last-of-type { border-bottom: none; }

        .form-group {
            display: flex;
            flex-direction: column;
            gap: 0.75rem;
            margin-bottom: 1rem;
        }

        label { font-weight: 600; font-size: 0.875rem; }

        input, select, textarea {
            padding: 0.5rem;
            border: 1px solid var(--border);
            border-radius: 4px;
            font-size: 1rem;
            width: 100%;
            box-sizing: border-box;
        }

        button {
            cursor: pointer;
            padding: 0.6rem 1rem;
            border-radius: 4px;
            font-weight: 600;
            transition: opacity 0.2s;
        }

        #add-expense {
            background-color: var(--primary);
            color: white;
            border: none;
            width: 100%;
        }

        button:hover { opacity: 0.9; }

        #form-error {
            color: var(--danger);
            font-size: 0.875rem;
            min-height: 1.25rem;
            margin-top: 0.5rem;
        }

        .filter-section {
            display: grid;
            grid-template-columns: 1fr 1fr 1fr;
            gap: 0.5rem;
            border-bottom: none;
        }

        .filter-section div { display: flex; flex-direction: column; gap: 4px; }
        .filter-section label { font-size: 0.75rem; text-transform: uppercase; color: #64748b; }

        .summary-section {
            display: flex;
            flex-wrap: wrap;
            gap: 1rem;
            border-bottom: none;
            align-items: center;
        }

        #total {
            font-size: 1.25rem;
            font-weight: 700;
            width: 100%;
            margin-bottom: 0.5rem;
        }

        .cat-total {
            background: #f1f5f9;
            padding: 4px 8px;
            border-radius: 4px;
            font-size: 0.875rem;
            font-weight: 500;
        }

        .expense-list {
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
        }

        .expense {
            display: grid;
            grid-template-columns: 1fr auto auto;
            align-items: center;
            padding: 0.75rem;
            background: #fff;
            border: 1px solid var(--border);
            border-radius: 4px;
        }

        .exp-info { display: flex; flex-direction: column; }
        .exp-date { font-size: 0.75rem; color: #64748b; }
        .exp-amount { font-weight: 700; text-align: right; padding-right: 1rem; }
        .exp-cat { font-size: 0.875rem; color: var(--primary); font-weight: 500; }

        .exp-del {
            background: #fee2e2;
            color: var(--danger);
            border: none;
            padding: 4px 8px;
            font-size: 0.75rem;
        }

        .exp-del:hover { background: #fecaca; }

        @media (max-width: 480px) {
            .filter-section { grid-template-columns: 1fr; }
        }
    </style>
</head>
<body>

<div id="app">
    <h1>Expense Tracker</h1>

    <!-- Entry Form -->
    <form id="expense-form" novalidate>
        <div class="form-group">
            <label for="amount">Amount</label>
            <input type="number" id="amount" step="0.01" placeholder="0.00">

            <label for="category">Category</label>
            <select id="category">
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>

            <label for="date">Date</label>
            <input type="date" id="date">

            <label for="note">Note (Optional)</label>
            <textarea id="note" rows="2"></textarea>
        </div>
        <button type="submit" id="add-expense">Add Expense</button>
        <div id="form-error"></div>
    </form>

    <!-- Filters -->
    <div class="filter-section">
        <div>
            <label>Category</label>
            <select id="filter-category">
                <option value="all">All</option>
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </div>
        <div>
            <label>From</label>
            <input type="date" id="filter-from">
        </div>
        <div>
            <label>To</label>
            <input type="date" id="filter-to">
        </div>
    </div>

    <!-- Summary -->
    <div class="summary-section">
        <div id="total">Total: 0.00</div>
        <div class="cat-total" data-cat="groceries">Groceries: 0.00</div>
        <div class="cat-total" data-cat="transport">Transport: 0.00</div>
        <div class="cat-total" data-cat="bills">Bills: 0.00</div>
        <div class="cat-total" data-cat="fun">Fun: 0.00</div>
    </div>

    <!-- List -->
    <div id="expense-list" class="expense-list">
        <!-- Rows injected here -->
    </div>
</div>

<script>
    // State Management
    let expenses = JSON.parse(localStorage.getItem('expenses')) || [];

    const form = document.getElementById('expense-folder') || document.getElementById('expense-form');
    const amountInput = document.getElementById('amount');
    const categoryInput = document.getElementById('category');
    const dateInput = document.getElementById('date');
    const noteInput = document.getElementById('note');
    const errorDiv = document.getElementById('form-error');
    const listContainer = document.getElementById('expense-list');
    const totalDisplay = document.getElementById('total');

    // Filter Elements
    const filterCat = document.getElementById('filter-category');
    const filterFrom = document.getElementById('filter-from');
    const filterTo = document.getElementById('filter-to');

    // Save to LocalStorage
    function save() {
        localStorage.setItem('expenses', JSON.stringify(expenses));
        render();
    }

    // Validation and Submission
    form.addEventListener('submit', (e) => {
        e.preventDefault();
        errorDiv.textContent = '';

        const amt = parseFloat(amountInput.value);
        const date = dateInput.filter ? null : dateInput.value; // Check if value exists
        const dateVal = dateInput.value;

        if (isNaN(amt) || amt <= 0) {
            errorDiv.textContent = 'Please enter a valid positive amount.';
            return;
        }

        if (!dateVal) {
            errorDiv.textContent = 'Please select a date.';
            return;
        }

        const newExpense = {
            id: Date.now(),
            amount: amt,
            category: categoryInput.value,
            date: dateVal,
            note: noteInput.value.trim()
        };

        expenses.push(newExpense);
        save();

        // Reset form fields
        amountInput.value = '';
        dateInput.value = '';
        noteInput.value = '';
        categoryInput.selectedIndex = 0;
    });

    // Delete functionality (Event Delegation)
    listContainer.addEventListener('click', (e) => {
        if (e.target.classList.contains('exp-del')) {
            const id = parseFloat(e.target.dataset.id);
            expenses = expenses.filter(exp => exp.id !== id);
            save();
        }
    });

    // Filter Listeners
    [filterCat, filterFrom, filterTo].forEach(el => {
        el.addEventListener('change', render);
    });

    function render() {
        const catVal = filterCat.value;
        const fromVal = filterFrom.value;
        const toVal = filterTo.value;

        // Filter logic
        const filtered = expenses.filter(exp => {
            const matchCat = (catVal === 'all' || exp.category === catVal);
            const matchFrom = !fromVal || exp.date >= fromVal;
            const matchTo = !toVal || exp.date <= toVal;
            return matchCat && matchFrom && matchTo;
        }).sort((a, b) => new Date(b.date) - new Date(a.date));

        // Render List
        listContainer.innerHTML = '';
        let runningTotal = 0;
        const catTotals = { groceries: 0, transport: 0, bills: 0, fun: 0 };

        filtered.forEach(exp => {
            runningTotal += exp.amount;
            catTotals[exp.category] += exp.amount;

            const row = document.createElement('div');
            row.className = 'expense';
            row.innerHTML = `
                <div class="exp-info">
                    <span class="exp-cat">${exp.category}</span>
                    <span class="exp-date">${exp.date} ${exp.note ? '• ' + exp.note : ''}</span>
                </div>
                <div class="exp-amount">${exp.amount.toFixed(2)}</div>
                <button class="exp-del" data-id="${exp.id}">Delete</button>
            `;
            listContainer.appendChild(row);
        });

        // Update Totals
        totalDisplay.textContent = `Total: ${runningTotal.toFixed(2)}`;

        // Update Category Summaries
        Object.keys(catTotals).forEach(cat => {
            const el = document.querySelector(`.cat-total[data-cat="${cat}"]`);
            if (el) {
                // Format text to include category name and value
                const label = cat.charAt(0).toUpperCase() + cat.slice(1);
                el.textContent = `${label}: ${catTotals[cat].toFixed(2)}`;
            }
        });
    }

    // Initial Load
    render();
</script>

</body>
</html>
